import { existsSync, mkdirSync, readFileSync, writeFileSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';
import { expect } from 'vitest';

const GOLDEN_DIR = join(dirname(fileURLToPath(import.meta.url)), '..', 'golden', 'style-transfer');

const UPDATE_ENV = 'UPDATE_STYLE_TRANSFER_GOLDEN_SNAPSHOTS';

/** Set `UPDATE_STYLE_TRANSFER_GOLDEN_SNAPSHOTS=1` to rewrite disk goldens from the current pipeline. */
export function assertGoldenPngEquals(actual: Buffer, baseName: string): void {
  mkdirSync(GOLDEN_DIR, { recursive: true });
  const path = join(GOLDEN_DIR, `${baseName}.png`);
  if (process.env[UPDATE_ENV] === '1' || process.env[UPDATE_ENV] === 'true') {
    writeFileSync(path, actual);
    return;
  }
  if (!existsSync(path)) {
    throw new Error(
      `Missing golden PNG: ${path}\nRegenerate with: ${UPDATE_ENV}=1 pnpm run a0 -- run @a0n/distributed-inference-host:test -- --testPathPattern=style-transfer-golden`,
    );
  }
  const expected = readFileSync(path);
  if (!actual.equals(expected)) {
    const preview = 48;
    const a0 = actual.subarray(0, preview).toString('hex');
    const e0 = expected.subarray(0, preview).toString('hex');
    throw new Error(
      `Golden PNG mismatch: ${baseName}.png (first ${preview} bytes)\nactual: ${a0}\nexpect: ${e0}\nRewrite with ${UPDATE_ENV}=1 if the pipeline change is intentional.`,
    );
  }
  expect(actual.length).toBeGreaterThan(32);
}
